module RefModule (
    input wire clk,
    input wire rst,
    input wire we,
    input wire [7:0] data_in,
    output reg [7:0] data_out
);
    reg [7:0] obf_gpio_state;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            obf_gpio_state <= 8'b00000000;
        end else if (we) begin
            obf_gpio_state <= data_in;
        end
    end

    always @(*) begin
        data_out = obf_gpio_state;
    end
endmodule
